/* MplatformOpenMapper.insertCopyRequest */ INSERT INTO MCP_REQUEST@DL_MCP (REQUEST_KEY ,MANAGER_CODE ,AGENT_CODE ,SERVICE_TYPE ,OPER_TYPE ,CSTMR_TYPE ,RES_CODE ,RES_MSG ,RES_NO ,CLAUSE_PRI_COLLECT_FLAG ,CLAUSE_PRI_OFFER_FLAG ,CLAUSE_ESS_COLLECT_FLAG ,CLAUSE_PRI_TRUST_FLAG ,CLAUSE_PRI_AD_FLAG ,CLAUSE_CONFIDENCE_FLAG ,ONLINE_AUTH_TYPE ,ONLINE_AUTH_INFO ,PSTATE ,REQUEST_STATE_CODE ,OPEN_NO ,FILE01 ,FILE01_MASK ,FAXYN ,FAXNUM
,ON_OFF_TYPE ,RIP ,OPEN_REQ_DATE ,SYS_RDATE ,REQ_WANT_NUMBER ,REQ_WANT_NUMBER2 ,REQ_WANT_NUMBER3 ,REQ_BUY_TYPE ,REQ_MODEL_NAME ,REQ_MODEL_COLOR ,REQ_PHONE_SN ,REQ_USIM_SN ,REQ_PAY_TYPE ,REQ_ADDITION ,SHOP_CD ,APP_FORM_YN ,REQ_IN_DAY ,CONTRACT_NUM ,ETC_SPECIAL ,REQ_USIM_NAME ,PHONE_PAYMENT ,REQ_ADDITION_PRICE ,APP_FORM_XML_YN ,SPC_CODE ,CNTPNT_SHOP_ID ,SHOP_USM_ID ,MEMO ,REC_YN ,OPEN_MARKET_REFERER ,SO_CD ,NW_BLCK_AGRM_YN ,APP_BLCK_AGRM_YN ,APP_CD ,SO_TRNS_AGRM_YN ,CLAUSE_JEHU_FLAG ,SHOP_NM ,PROD_ID ,CRET_ID ,BANNER_CD ,SNTY_COLOR_CD ,SNTY_CAPAC_CD ,PROD_TYPE ,CLAUSE_RENTAL_MODEL_CP ,CLAUSE_RENTAL_MODEL_CP_PR ,CLAUSE_RENTAL_SERVICE ,CLAUSE_MPPS35_FLAG ,CLAUSE_FINANCE_FLAG ,RVISN_ID ,RVISN_DTTM ,PROMOTION_CD ) SELECT #{requestKey} ,MANAGER_CODE ,AGENT_CODE ,SERVICE_TYPE ,OPER_TYPE ,CSTMR_TYPE ,RES_CODE ,RES_MSG ,#{resNo} ,CLAUSE_PRI_COLLECT_FLAG ,CLAUSE_PRI_OFFER_FLAG ,CLAUSE_ESS_COLLECT_FLAG ,CLAUSE_PRI_TRUST_FLAG ,CLAUSE_PRI_AD_FLAG ,CLAUSE_CONFIDENCE_FLAG ,ONLINE_AUTH_TYPE ,ONLINE_AUTH_INFO ,'00' ,'00' ,OPEN_NO ,FILE01 ,FILE01_MASK ,FAXYN ,FAXNUM
,ON_OFF_TYPE ,RIP ,OPEN_REQ_DATE ,SYSDATE ,REQ_WANT_NUMBER ,REQ_WANT_NUMBER2 ,REQ_WANT_NUMBER3 ,REQ_BUY_TYPE ,REQ_MODEL_NAME ,REQ_MODEL_COLOR ,REQ_PHONE_SN ,REQ_USIM_SN ,REQ_PAY_TYPE ,REQ_ADDITION ,SHOP_CD ,APP_FORM_YN ,SYSDATE ,CONTRACT_NUM ,ETC_SPECIAL ,REQ_USIM_NAME ,PHONE_PAYMENT ,REQ_ADDITION_PRICE ,APP_FORM_XML_YN ,SPC_CODE ,CNTPNT_SHOP_ID ,SHOP_USM_ID ,MEMO ,REC_YN ,OPEN_MARKET_REFERER ,SO_CD ,NW_BLCK_AGRM_YN ,APP_BLCK_AGRM_YN ,APP_CD ,SO_TRNS_AGRM_YN ,CLAUSE_JEHU_FLAG ,SHOP_NM ,PROD_ID ,CRET_ID ,BANNER_CD ,SNTY_COLOR_CD ,SNTY_CAPAC_CD ,PROD_TYPE ,CLAUSE_RENTAL_MODEL_CP ,CLAUSE_RENTAL_MODEL_CP_PR ,CLAUSE_RENTAL_SERVICE ,CLAUSE_MPPS35_FLAG ,CLAUSE_FINANCE_FLAG ,'BATCH' ,SYSDATE ,PROMOTION_CD FROM MCP_REQUEST@DL_MCP WHERE REQUEST_KEY = #{oldRequestKey}

mapper.update:
/* MplatformOpenMapper.updateRequestState */
UPDATE  MCP_REQUEST@DL_MCP
SET     PSTATE = '30'
        , RVISN_ID = 'BATCH'
        , RVISN_DTTM = SYSDATE
WHERE   REQUEST_KEY = #{oldRequestKey}

mapper.insert:
/* MplatformOpenMapper.insertRequestOsstHist */
INSERT INTO MCP_REQUEST_OSST@DL_MCP (
    MVNO_ORD_NO
    , SEQ
    , OSST_ORD_NO
    , PRGR_STAT_CD
    , CUST_ID
    , SVC_CNTR_NO
    , RSLT_CD
    , RSLT_MSG
    , NSTEP_GLOBAL_ID
    , RSLT_DT
    , TLPH_NO_STAT_CD
    , ASGN_AGNC_ID
    , TLPH_NO_OWN_CMPN_CD
    , OPEN_SVC_IND_CD
    , ENCD_TLPH_NO
    , TLPH_NO
    , IF_TYPE
    , REGST_DTTM
) VALUES (
    LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0')
    , (SELECT MAX(SEQ) + 1 FROM MCP_REQUEST_OSST@DL_MCP WHERE MVNO_ORD_NO = LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0'))
    , (SELECT MAX(OSST_ORD_NO) FROM MCP_REQUEST_OSST@DL_MCP WHERE MVNO_ORD_NO = LPAD(#{resNo, jdbcType=VARCHAR}, 14, '0') AND PRGR_STAT_CD = 'PC2' AND RSLT_CD = '0000')
    , #{appEventCd, jdbcType=VARCHAR}
    , #{customerId, jdbcType=VARCHAR}
    , #{svcCntrNo, jdbcType=VARCHAR}
    , NVL(#{rsltCd, jdbcType=VARCHAR}, '0000')
    , #{rsltMsg, jdbcType=VARCHAR}
    , #{nstepGlobalId, jdbcType=VARCHAR}
    , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
    , #{tlphNoStatCd, jdbcType=VARCHAR}
    , #{asgnAgncId, jdbcType=VARCHAR}
    , #{tlphNoOwnCmpnCd, jdbcType=VARCHAR}
    , #{openSvcIndCd, jdbcType=VARCHAR}
    , #{encdTlphNo, jdbcType=VARCHAR}
    , #{tlphNo, jdbcType=VARCHAR}
    , NVL(#{gubun}, 'WEB')
    , SYSDATE
)

mapper.update:
/* MplatformOpenMapper.updateMcpRequest */
UPDATE  MCP_REQUEST@DL_MCP
SET     REQUEST_STATE_CODE = '21'
WHERE   REQUEST_KEY = #{requestKey}

/* MplatformOpenMapper.updateJuoSubInfo */
UPDATE  MSP_JUO_SUB_INFO
SET     SUB_ADR_ZIP = #{zipCd, jdbcType=VARCHAR}
        , SRL_IF_ID = #{resNo, jdbcType=VARCHAR}
        , MNP_IND_CD = #{mnpIndCd, jdbcType=VARCHAR}
        , SCAN_ID = #{scanId, jdbcType=VARCHAR}
        , ON_OFF_TYPE = #{onOffType, jdbcType=VARCHAR}
        , OSST_YN = 'Y' 
WHERE   CONTRACT_NUM = #{svcCntrNo}

